// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import java.util.List;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.Future;
import java.util.concurrent.TimeUnit;

import org.junit.jupiter.api.Test;

class LmdbNativeElasticTaskAdmissionTest {

	private static final String MAX_TASKS_FLAG = "rdf4j.lmdb.parallel.maxTasks";

	@Test
	void elasticReservationGrantsLargestCompleteGroupForMode() {
		String previous = System.getProperty(MAX_TASKS_FLAG);
		try {
			System.setProperty(MAX_TASKS_FLAG, "5");

			try (LmdbNativeParallelPipelines.TaskReservation first = LmdbNativeParallelPipelines
					.tryReserveTasks(false, 4)) {
				assertThat(first.grantedWorkers()).isEqualTo(4);
				assertThat(LmdbNativeParallelPipelines.tryReserveTasks(true, 4))
						.as("morsel mode must not admit a single worker")
						.isNull();
				try (LmdbNativeParallelPipelines.TaskReservation degraded = LmdbNativeParallelPipelines
						.tryReserveTasks(false, 4)) {
					assertThat(degraded.grantedWorkers())
							.as("range mode can use the last worker slot")
							.isEqualTo(1);
				}
			}

			try (LmdbNativeParallelPipelines.TaskReservation released = LmdbNativeParallelPipelines
					.tryReserveTasks(true, 4)) {
				assertThat(released.grantedWorkers()).isEqualTo(4);
			}
		} finally {
			if (previous == null) {
				System.clearProperty(MAX_TASKS_FLAG);
			} else {
				System.setProperty(MAX_TASKS_FLAG, previous);
			}
		}
	}

	@Test
	void simultaneousRangeRequestsBothReceiveNonzeroWorkerGrants() throws Exception {
		String previous = System.getProperty(MAX_TASKS_FLAG);
		ExecutorService executor = Executors.newFixedThreadPool(2);
		try {
			System.setProperty(MAX_TASKS_FLAG, "5");
			CountDownLatch start = new CountDownLatch(1);
			CountDownLatch acquired = new CountDownLatch(2);
			CountDownLatch release = new CountDownLatch(1);

			Future<Integer> first = executor.submit(() -> concurrentGrant(start, acquired, release));
			Future<Integer> second = executor.submit(() -> concurrentGrant(start, acquired, release));
			start.countDown();
			assertThat(acquired.await(10, TimeUnit.SECONDS)).isTrue();
			release.countDown();
			assertThat(List.of(first.get(), second.get())).containsExactlyInAnyOrder(4, 1);
		} finally {
			executor.shutdownNow();
			if (previous == null) {
				System.clearProperty(MAX_TASKS_FLAG);
			} else {
				System.setProperty(MAX_TASKS_FLAG, previous);
			}
		}
	}

	@Test
	void parallelStrategyLabelsExposeActualGrantedWorkers() {
		assertThat(LmdbNativeParallelPipelines
				.parallelStrategyLabel(LmdbNativeAttemptMetrics.PATH_PARALLEL_PIPELINES, 1, 4))
						.isEqualTo("parallelPipelines(workers=1,rangePartitioned=4)");
		assertThat(LmdbNativeParallelPipelines
				.parallelStrategyLabel(LmdbNativeAttemptMetrics.PATH_PARALLEL_AGGREGATION, 2, 0))
						.isEqualTo("parallelAggregation(workers=2)");
	}

	private static int concurrentGrant(CountDownLatch start, CountDownLatch acquired, CountDownLatch release)
			throws InterruptedException {
		start.await();
		try (LmdbNativeParallelPipelines.TaskReservation reservation = LmdbNativeParallelPipelines
				.tryReserveTasks(false, 4)) {
			int granted = reservation == null ? 0 : reservation.grantedWorkers();
			acquired.countDown();
			release.await();
			return granted;
		}
	}
}
